  import java.io.File;
  import java.io.FileNotFoundException;
  import java.util.ArrayList;
  import java.util.HashMap;
  import java.util.List;
  import java.util.Map;
  import java.util.Scanner;

  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  import sailpoint.api.SailPointContext;
  import sailpoint.api.SailPointFactory;
  import sailpoint.object.Attributes;
  import sailpoint.object.Identity;
  import sailpoint.object.TaskResult;
  import sailpoint.tools.GeneralException;
  import sailpoint.tools.Message;
  import sailpoint.tools.Util;

  Log logger = LogFactory.getLog("sailpoint.ascension.task.InternalIdLog.AscensionRuleAMITAUpdateInternalID");
  List successUserNames = new ArrayList();
  List failedUserNames = new ArrayList();
  List successChildPersonaNames = new ArrayList();
  List failedChildPersonaNames = new ArrayList();
  List modifiedSIDsList = new ArrayList();
  List errorMessages = new ArrayList();
  
  public void writeAuditRecords(String userName, String oldInternalId, String newInternalId){
    String auditString1 = "Internal ID changed for identity " + userName;
	String auditString2 = "Internal ID changed from " + oldInternalId + " to " + newInternalId;
	String auditString3 = "Changed by " + launcher;
	writeAuditRecordToIIQ("UpdateInternalID" ,auditString1, auditString2,auditString3,userName,"Update InternalID");
  }

  public void updateUsersInternalIDs(List userNameList, List failedUserNames, List successUserNames, Log logger) throws GeneralException {
    logger.debug("Entering method updateUsersInternalIDs");
    if (userNameList == null || userNameList.isEmpty()){
	  return null;
	}
	int lineCount = 0;
    for (String userName : userNameList) {
	
	  lineCount++;
	  if ((lineCount % 20) == 0) { context.decache(); }
	  
      Identity identity = context.getObjectByName(Identity.class, userName);
      if (null == identity) {
	    setErrorMessages(userName, "Identity not found for this user" , "", true);
      }
      else {
		if(hasNoValidEntry){
		  hasNoValidEntry = false;
		}
        String personaType = identity.getStringAttribute("personaType");
        String oldInternalId = identity.getStringAttribute("internalId");
        /*
         * Check if primary 
         * Create new or update old internal id based on the internal id format
		 * Get the child personas of the parent persona and update its internal id
         */
        if (Util.isNotNullOrEmpty(personaType) && "Primary".equalsIgnoreCase(personaType)) {
          String newInternalId = createOrUpdateParentInternalID(oldInternalId, userName);
          identity.setAttribute("internalId", newInternalId);
          context.saveObject(identity);
          context.commitTransaction();
		  modifiedSIDsList.add("idName: " + userName + "|| oldInternalId: " + oldInternalId + " || newInternalId: " + newInternalId);
		  //write audits to iiq
		  writeAuditRecords(userName, oldInternalId, newInternalId);
          successUserNames.add(userName);
          List childPersonaNames = identity.getAttribute("childPersonaNames");
          if(childPersonaNames != null && !childPersonaNames.isEmpty()) {
            for (String childPersonaName : childPersonaNames) {
              try {
                Identity childIdentity = context.getObjectByName(Identity.class, childPersonaName);
                if(childIdentity != null) {
                  childIdentity.setAttribute("parentPersonaSID", newInternalId);
				  oldChildInternalId = childIdentity.getStringAttribute("internalId");
				  String newChildInternalId = updateChildInternalID(childPersonaName, userName, newInternalId, oldChildInternalId);
				  modifiedSIDsList.add("idName: " + childPersonaName + " || oldChildInternalId: " + oldChildInternalId + " || newChildInternalId: " + newChildInternalId);
				  //write audits to iiq
			      writeAuditRecords(childPersonaName, oldInternalId, newInternalId);
				  successChildPersonaNames.add(childPersonaName);
                } else {
				  setErrorMessages(userName, "Child Persona Identity is not found" , childPersonaName, false);
                }
              }
              catch(Exception ex) {
			    setErrorMessages(userName, "failed to set Parent SID for the child identity" , childPersonaName, false);
                logger.error(ex.getMessage());
              }
            }
          }
        }

        /*
         * check if child, fetch parentSID, generate the childSID, replace the childSID in the parent identity
         */
        else if (Util.isNotNullOrEmpty(personaType) && "Child".equalsIgnoreCase(personaType)) {
          String parentPersonaSID = identity.getStringAttribute("parentPersonaSID");
          String parentPersonaName = identity.getStringAttribute("parentPersonaName");
          Identity parentIdentity = context.getObjectByName(Identity.class, parentPersonaName);
    	  if (parentIdentity == null) {
		    setErrorMessages(userName, "parentIdentity not found" , parentPersonaName, true);
    	  }
          else if (Util.isNullOrEmpty(parentPersonaSID) || !parentPersonaSID.contains("-")) {
            setErrorMessages(userName, "parentPersonaSID is blank or not in correct format", parentPersonaSID, true);
          }
          else if(oldInternalId.contains("-")) {
		    setErrorMessages(userName, "skipped childPersona since SID has already been updated", oldInternalId, true);
		  } 
          else {
            String newInternalId = updateChildInternalID(userName, parentPersonaName, parentPersonaSID, oldInternalId);
            modifiedSIDsList.add("idName: " + userName + " || oldChildInternalId: " + oldInternalId + " || newChildInternalId: " + newInternalId);
			//write audits to iiq
		    writeAuditRecords(userName, oldInternalId, newInternalId);
            successUserNames.add(userName); 
          }
        }
        else if(Util.isNullOrEmpty(personaType) || ( !"Primary".equalsIgnoreCase(personaType) && !"Child".equalsIgnoreCase(personaType))) {
		  setErrorMessages(userName, "PersonaType is blank or incorrect", personaType, true);
        }
      }
    }
	logger.debug("Exiting method updateUsersInternalIDs");
  }
  
  public void setErrorMessages(String userName, String message, String parentNameOrChildNameOrInternalID, boolean addToFailedUserNamesList){
    if(addToFailedUserNamesList) {
	  failedUserNames.add(userName);
	  logger.error("failedUserName: " + userName);
	} else {
      failedChildPersonaNames.add(parentNameOrChildNameOrInternalID);
	}
	String value = "UserName: " + userName + " || " + message;
	if(!Util.isNullOrEmpty(parentNameOrChildNameOrInternalID)){
	  value = value + ": " + parentNameOrChildNameOrInternalID;
	}
    errorMessages.add(value);
    logger.error(value); 
  }

  public void readInputFileandUpdateInternalID(String filePath) throws GeneralException {
    logger.debug("Entering method readInputFileandUpdateInternalID");

    int lineCount = 0;
    String headerString = null;
    int headerLength = 0;
    List allUsersList = new ArrayList();
    String[] headerSplit = null;
    Scanner sc = null;
    try {
      if (Util.isNotNullOrEmpty(filePath)) {
        File file = new File(filePath);
        if (!file.exists() || file.isDirectory()) {
          logger.error("File doesnt exist");
          taskResult.addMessage(new Message(Message.Type.Warn, "Input file does not exist : " + filePath, null));
          return null;
        }
        try {
          sc = new Scanner(file);
        }
        catch (FileNotFoundException fnex) {
          logger.error("FileNotFoundException : " + fnex.getMessage());
          taskResult.addMessage(new Message(Message.Type.Error, "File not found " + fnex.getMessage(), null));
        }
        Identity identity = null;
        List userNameList = new ArrayList();
        while (sc.hasNextLine()) {
          String line = sc.nextLine();
          if (lineCount == 0) {
            headerString = line;
            lineCount++;
            continue;
          }
          if (Util.isNotNullOrEmpty(line)){
		    userNameList.add(line);
		  }
          lineCount++;
        }
        updateUsersInternalIDs(userNameList, failedUserNames, successUserNames, logger);
      }
    }
    catch (Exception ex) {
      logger.error("Exception readInputFile :: " + ex.getMessage());
      taskResult.addMessage(new Message(Message.Type.Error, "Exception : " + ex.getMessage(), null));
    }
    finally {
      if (sc != null){
        sc.close();
	  }
    }
    logger.debug("Exiting method readInputFileandUpdateInternalID");
  }
  /**** Main method ****/
  logger.debug("Starting main method || rule:  Ascension-Rule-AMITA-UpdateInternalID");
  String fileLocation = "";
  String userNamesInCSV = "";
  String launcher = taskResult.getLauncher();
  boolean hasNoValidEntry = true;

  if (taskResult == null) {
    taskResult = new TaskResult();
    taskResult.setName("Ascension-AMITA-UpdateInternalID");
  }
  if (null != config && config instanceof Map && !config.isEmpty()) {
    logger.debug("rule:  Ascension-Rule-AMITA-UpdateInternalID || config: " + config.toString());
    fileLocation = config.get("filePath");
    userNamesInCSV = config.get("usernameCSVList");
	if (Util.isNullOrEmpty(fileLocation) && Util.isNullOrEmpty(userNamesInCSV)) {
		taskResult.addMessage(new Message(Message.Type.Error, "No input received", null));
    }
    if (Util.isNotNullOrEmpty(fileLocation)) {
      taskResult.setAttribute("fileLocation", fileLocation);
      readInputFileandUpdateInternalID(fileLocation);
    }
    else if (Util.isNotNullOrEmpty(userNamesInCSV)) {
      taskResult.setAttribute("userNamesInCSV", userNamesInCSV);
      List userNameList = Util.csvToList(userNamesInCSV);
      updateUsersInternalIDs(userNameList, failedUserNames, successUserNames, logger);
    }
  }
  if ((!Util.isNullOrEmpty(fileLocation) || !Util.isNullOrEmpty(userNamesInCSV)) && hasNoValidEntry) {
    taskResult.addMessage(new Message(Message.Type.Error, "No valid username found", null));
  }

  taskResult.setAttribute("successUserNames", successUserNames);
  taskResult.setAttribute("failedUserNames", failedUserNames);
  taskResult.setAttribute("successChildPersonaNames", successChildPersonaNames);
  taskResult.setAttribute("failedChildPersonaNames", failedChildPersonaNames);
  taskResult.setAttribute("modifiedSIDs", modifiedSIDsList);
  taskResult.setAttribute("errorMessages", errorMessages);
